import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"

const messages = [
  {
    name: "Emily Davis",
    message: "Booking Inquiry",
    time: "2 hours ago",
    avatar: "ED",
  },
  {
    name: "David Martinez",
    message: "Listing Activation Request",
    time: "1 day ago",
    avatar: "DM",
  },
  {
    name: "Jessica Lee",
    message: "Payment Issue",
    time: "3 days ago",
    avatar: "JL",
  },
  {
    name: "Daniel Taylor",
    message: "New Storage Listing",
    time: "5 days ago",
    avatar: "DT",
  },
]

export function MessagesSection() {
  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <CardTitle>Messages</CardTitle>
        <Button variant="link" className="text-blue-600">
          View all
        </Button>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {messages.map((message, index) => (
            <div key={index} className="flex items-center gap-3">
              <Avatar className="h-10 w-10">
                <AvatarImage src="/placeholder.svg" alt={message.name} />
                <AvatarFallback className="bg-gray-100">{message.avatar}</AvatarFallback>
              </Avatar>
              <div className="flex-1">
                <p className="font-medium text-sm">{message.name}</p>
                <p className="text-sm text-gray-600">{message.message}</p>
              </div>
              <span className="text-xs text-gray-400">{message.time}</span>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  )
}
